sequence.script:
        var initPayload = mc.getPayloadJSON();
var payload = {
	"payment_method": initPayload.payment_method,
	"return_url": 'http://localhost:8081/api'
};
mc.setPayloadJSON(payload);

then.script:
var backendResponse = mc.getPayloadJSON();
var initPayload = JSON.parse(mc.getProperty('initPayload'));
var response = {
  "paymentIntentid": backendResponse.id,
  "transactionId": backendResponse.latest_charge,
  "amount": (backendResponse.amount/100),
  "currency": backendResponse.currency,
  "capture_method": backendResponse.capture_method,
  "confirmation_method": backendResponse.capture_method,
  "created": ((new Date(Number(backendResponse.created) * 1000)).toISOString().split('.')[0] + "Z"),
  "paymentMethod": backendResponse.payment_method,
  "status": backendResponse.status
}
// Conditionally add fields if they exist
if (initPayload.policyNumber != null && initPayload.policyNumber != undefined) {
	response.policyNumber = initPayload.policyNumber;
}

if (initPayload.quoteId != null && initPayload.quoteId != undefined) {
	response.quoteId = initPayload.quoteId;
}        
if (initPayload.partyIdentifier != null && initPayload.partyIdentifier != undefined) {
	response.partyIdentifier = initPayload.partyIdentifier;
}        

mc.setPayloadJSON(response);
